    {
      "cell_type": "markdown",
      "metadata": {
        "id": "a2bb8158"
      },
      "source": [
        "Finally, let's visualize the clustered data to see the results. Each cluster will be represented by a different color."
      ]
    },
    {
      "cell_type": "code",
      "metadata": {
        "colab": {
          "base_uri": "https://localhost:8080/",
          "height": 641
        },
        "id": "7ccc6f40",
        "outputId": "5b5f8df3-ef53-4d4d-f687-3af0a7364d2d"
      },
      "source": [
        "plt.figure(figsize=(10, 7))\n",
        "sns.scatterplot(x='Feature_1', y='Feature_2', hue='Cluster', data=df, palette='viridis', s=100, alpha=0.8)\n",
        "plt.scatter(kmeans.cluster_centers_[:, 0], kmeans.cluster_centers_[:, 1], s=300, c='red', marker='X', label='Centroids')\n",
        "plt.title('K-Means Clustering Results (k=3)')\n",
        "plt.xlabel('Feature 1')\n",
        "plt.ylabel('Feature 2')\n",
        "plt.legend()\n",
        "plt.grid(True)\n",
        "plt.show()"
      ],
      "execution_count": null,
      "outputs": [
        {
          "output_type": "display_data",
          "data": {
            "text/plain": [
              "<Figure size 1000x700 with 1 Axes>"
            ],
            "image/png": "\n"
          },
          "metadata": {}
        }
      ]
    },
